/// Result of convention-based setup file discovery.
///
/// Convention locations checked:
/// - Session: `shatter.setup.{ext}` in project root, or `.shatter/setup.{ext}`
/// - File-level: `<stem>.shatter.setup.{ext}` co-located with each source file
#[derive(Debug, Clone, PartialEq)]
pub struct DiscoveredSetupFiles {
    /// Session-level setup file found by convention (absolute path).
    pub session_setup: Option<PathBuf>,
    /// Source file path → co-located setup file path (both absolute).
    pub file_setups: HashMap<PathBuf, PathBuf>,
}

/// Discover setup files by convention in a project directory.
///
/// Scans `project_root` for convention-named setup files matching `language_ext`
/// (without leading dot, e.g. `"ts"`, `"go"`, `"rs"`).
///
/// If `config` is provided and already specifies setup files at a given level,
/// convention discovery is skipped for that level — explicit config always wins.
///
/// `source_files` are the source files to check for co-located file-level setups.
pub fn discover_setup_files(
    project_root: &Path,
    language_ext: &str,
    config: Option<&ShatterConfig>,
    source_files: &[PathBuf],
) -> DiscoveredSetupFiles {
    let config_has_session = config
        .map(|c| c.defaults.session_setup.is_some())
        .unwrap_or(false);
    let config_has_file_setup = config
        .map(|c| c.defaults.file_setup.as_ref().is_some_and(|fs| !fs.is_empty()))
        .unwrap_or(false);

    // Session-level: check project_root/shatter.setup.{ext} then .shatter/setup.{ext}
    let session_setup = if config_has_session {
        None
    } else {
        let root_convention = project_root.join(format!("shatter.setup.{language_ext}"));
        let dot_shatter_convention = project_root
            .join(".shatter")
            .join(format!("setup.{language_ext}"));

        if root_convention.is_file() {
            Some(root_convention)
        } else if dot_shatter_convention.is_file() {
            Some(dot_shatter_convention)
        } else {
            None
        }
    };

    // File-level: check <stem>.shatter.setup.{ext} co-located with each source file
    let file_setups = if config_has_file_setup {
        HashMap::new()
    } else {
        let mut setups = HashMap::new();
        for source in source_files {
            if let Some(stem) = source.file_stem().and_then(|s| s.to_str()) {
                if let Some(parent) = source.parent() {
                    let setup_path =
                        parent.join(format!("{stem}.shatter.setup.{language_ext}"));
                    if setup_path.is_file() {
                        setups.insert(source.clone(), setup_path);
                    }
                }
            }
        }
        setups
    };

    DiscoveredSetupFiles {
        session_setup,
        file_setups,
    }
}

